import{_ as r,o as a,c as t,ae as o}from"./chunks/framework.BGHOrOyn.js";const i="/gitbook-personnal-docs/assets/Connection-Diagram-R1.DlIdZJcr.png",p=JSON.parse('{"title":"Connection Diagrams","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/pixhawk/connection-diagrams.md","filePath":"robotics/pixhawk/connection-diagrams.md"}'),n={name:"robotics/pixhawk/connection-diagrams.md"};function s(d,e,l,h,u,c){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="connection-diagrams" tabindex="-1">Connection Diagrams <a class="header-anchor" href="#connection-diagrams" aria-label="Permalink to &quot;Connection Diagrams&quot;">​</a></h1><figure><img src="'+i+'" alt=""><figcaption></figcaption></figure><p>The following connection diagrams show how to connect devices to the ArduSub control system.</p><p>Power distribution is not shown other than the power requirements for each device so as to illustrate clean connections. Where a voltage is not known, a &quot;+Vin&quot; is shown. The maximum voltage should be in accordance with the manufacturers specifications.</p><p>For more details on connections, the manufacturer&#39;s product pages and documentation should be referenced.</p><h2 id="minimum-required-and-recommended-hardware" tabindex="-1">Minimum Required and Recommended Hardware <a href="#minimum-required-and-recommended-hardware" id="minimum-required-and-recommended-hardware"></a> <a class="header-anchor" href="#minimum-required-and-recommended-hardware" aria-label="Permalink to &quot;Minimum Required and Recommended Hardware &lt;a href=&quot;#minimum-required-and-recommended-hardware&quot; id=&quot;minimum-required-and-recommended-hardware&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><ul><li>Components are not shown to scale, some are enlarged to show connection locations.</li><li>For clarity reasons, power distribution connections are not shown but the input voltage ranges are.</li></ul><h3 id="required-hardware-overview" tabindex="-1">Required Hardware Overview <a href="#required-hardware-overview" id="required-hardware-overview"></a> <a class="header-anchor" href="#required-hardware-overview" aria-label="Permalink to &quot;Required Hardware Overview &lt;a href=&quot;#required-hardware-overview&quot; id=&quot;required-hardware-overview&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><ul><li><a href="http://www.ardusub.com/introduction/hardware-options/required-hardware/autopilot.html" target="_blank" rel="noreferrer">Autopilot</a>: The autopilot board/flight controller board processes the pilot input and sensor data, and controls the motors, lights, servos, and relays on the vehicle. It runs the <a href="http://www.ardusub.com/introduction/required-software/ardusub-autopilot-firmware.html" target="_blank" rel="noreferrer">ArduSub firmware</a>.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/required-hardware/companion-computer.html" target="_blank" rel="noreferrer">Companion Computer</a>: The Companion Computer streams video to the <a href="http://www.ardusub.com/introduction/hardware-options/required-hardware/topside-computer.html" target="_blank" rel="noreferrer">Topside Computer</a>, and relays <a href="https://ardupilot.org/dev/docs/mavlink-basics.html" target="_blank" rel="noreferrer">MAVLink</a> communications between the autopilot and the Topside Computer via Ethernet.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/required-hardware/topside-computer.html" target="_blank" rel="noreferrer">Topside Computer</a>: The topside computer is where the live video feed and telemetry information are received and displayed. It accepts operator input from a joystick to allow controlling the connected vehicle.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/required-hardware/joystick.html" target="_blank" rel="noreferrer">Joystick</a>: A joystick allows the operator to control the vehicle, using stick control movements and button presses.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/required-hardware/camera.html" target="_blank" rel="noreferrer">Camera</a>: The camera allows the pilot to see and record from the vehicle&#39;s point of view. If paired with a <a href="http://www.ardusub.com/introduction/hardware-options/recommended-extras/camera-gimbal.html" target="_blank" rel="noreferrer">Camera Tilt Mount</a> or other gimbal it can be moved during operation.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/required-hardware/escs.html" target="_blank" rel="noreferrer">Electronic Speed Controls (ESCs)</a>: ESCs are used to control the speed/thrust of motors and <a href="http://www.ardusub.com/introduction/hardware-options/required-hardware/thrusters.html" target="_blank" rel="noreferrer">thrusters</a>.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/required-hardware/thrusters.html" target="_blank" rel="noreferrer">Thrusters</a>: Thrusters are necessary to maneuver an underwater vehicle around. The number and orientation of thrusters on a vehicle determines the number of degrees of freedom (DoF) it may maneuver in.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/required-hardware/power-sensing-module.html" target="_blank" rel="noreferrer">Power Sensing Module</a>: A power sensing module provides analog current and voltage sensing to an autopilot onboard the vehicle. It&#39;s used to measure battery level, and how much power the vehicle is using.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/required-hardware/power-supply.html" target="_blank" rel="noreferrer">Power Supply</a>: The power supply and distribution system powers all the onboard electronics, including the high current draw of the thrusters. A regulator converts the main supplied power (from a battery or otherwise) into appropriate voltages for the more sensitive electronics - it must ensure a steady supply to avoid the computers restarting and losing control of the vehicle.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/required-hardware/tether.html" target="_blank" rel="noreferrer">Tether</a>: A tether is a length of cable which connects the Companion Computer to the Topside Computer. It allows low latency high-bandwidth communication to a vehicle in water, which other technologies are poorly suited to.</li></ul><h4 id="recommended-extras-overview" tabindex="-1">Recommended Extras Overview <a href="#recommended-extras-overview" id="recommended-extras-overview"></a> <a class="header-anchor" href="#recommended-extras-overview" aria-label="Permalink to &quot;Recommended Extras Overview &lt;a href=&quot;#recommended-extras-overview&quot; id=&quot;recommended-extras-overview&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li><a href="http://www.ardusub.com/introduction/hardware-options/recommended-extras/pressure-sensor.html" target="_blank" rel="noreferrer">Pressure Sensor</a>: An external pressure sensor is required for estimating the vehicle&#39;s depth. They often come with a simple temperature sensor included.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/recommended-extras/camera-gimbal.html" target="_blank" rel="noreferrer">Camera Tilt Mount</a>: A camera tilt mount or other gimbal is used for moving and/or stabilising the camera, for smoother video feeds and looking around without needing to rotate or move the whole vehicle.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/recommended-extras/lights.html" target="_blank" rel="noreferrer">Lights</a>: Lights are important for visual inspections and navigation, especially at night time, under cover, or at depths where sunlight doesn&#39;t reach.</li></ul><h4 id="additional-peripheral-devices-overview" tabindex="-1">Additional Peripheral Devices Overview <a href="#additional-peripheral-devices-overview" id="additional-peripheral-devices-overview"></a> <a class="header-anchor" href="#additional-peripheral-devices-overview" aria-label="Permalink to &quot;Additional Peripheral Devices Overview &lt;a href=&quot;#additional-peripheral-devices-overview&quot; id=&quot;additional-peripheral-devices-overview&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><ul><li><a href="http://www.ardusub.com/introduction/hardware-options/additional-peripheral-devices/leak-sensor.html" target="_blank" rel="noreferrer">Leak Sensors</a>: Leak sensors help to detect and warn about if a leak occurs, before it gets to and damages the electronics in an enclosure.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/additional-peripheral-devices/temperature-sensor.html" target="_blank" rel="noreferrer">Temperature Sensor</a>: An auxiliary temperature sensor can be connected to obtain faster and more accurate readings than from an integrated pressure sensor. This can be helpful in research, or where accurate temperature is important for estimating some other related phenomenon.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/additional-peripheral-devices/servos.html" target="_blank" rel="noreferrer">Servos</a>: Servos are useful when a component needs to be actuated or rotated. They can be inside an enclosure to rotate things such as cameras, or depth-rated and used outside of enclosures.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/additional-peripheral-devices/relays.html" target="_blank" rel="noreferrer">Relays</a>: Relays are useful for turning higher voltage (&gt;5V DC) auxiliary equipment on and off.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/additional-peripheral-devices/grippers-and-manipulators.html" target="_blank" rel="noreferrer">Grippers and Manipulators</a>: A gripper is a useful tool for picking up small objects, attaching recovery lines, or freeing a snagged tether. Other manipulators may be useful in cleaning, inspection, or repair tasks.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/additional-peripheral-devices/underwater-positioning.html" target="_blank" rel="noreferrer">Underwater Positioning and GPS (SBL and USBL)</a>: A positioning system is useful for navigation (going to a location, displaying the current position on a map), as well as location-tagging collected data.</li><li><a href="http://www.ardusub.com/introduction/hardware-options/additional-peripheral-devices/sonars.html" target="_blank" rel="noreferrer">Sonars</a>: Sonars are useful where visibility is low, for getting range measurements to surfaces or acoustically imaging targets. They can be helpful for navigation, especially in structured environments with no alternative positioning system.</li></ul>',13)])])}const w=r(n,[["render",s]]);export{p as __pageData,w as default};
